func landLocked(projectRoot string, req LandRequest, gitOps LandingGitOps, prep *landPrepState) (*LandResult, string, error) {
	if prep == nil {
		return nil, "", fmt.Errorf("missing land prep state")
	}

	var result *LandResult
	var syncFromRev string
	err := withMainGitLock(projectRoot, "land_ref_update", func() error {
		lockedTip, err := gitOps.ResolveRef(prep.worktreeDir, prep.targetRef)
		if err != nil {
			return fmt.Errorf("resolving target tip %s: %w", prep.targetRef, err)
		}
		if lockedTip != prep.currentTip {
			return errLandTargetTipMoved
		}

		// Fast path: no sibling advanced the target branch → straight ff via
		// update-ref. The worker's commit becomes the new tip unchanged; its
		// parent is still BaseRev, so replay sees the same inputs the worker
		// saw. No merge commit is created.
		if prep.currentTip == req.BaseRev {
			if err := gitOps.UpdateRefTo(prep.worktreeDir, prep.targetRef, req.ResultRev, lockedTip); err != nil {
				return fmt.Errorf("fast-forwarding %s to %s: %w", prep.targetRef, req.ResultRev, err)
			}
			result = &LandResult{
				Status:            "landed",
				NewTip:            req.ResultRev,
				LandedTip:         req.ResultRev,
				TargetBranch:      prep.targetBranch,
				Merged:            false,
				MergedCommitCount: prep.contribCount,
			}
			finalWD, cleanup, err := landingFinalizationWorktree(projectRoot, prep.worktreeDir, prep.targetBranch, gitOps)
			if err != nil {
				return err
			}
			defer cleanup()
			if preserved, syncRev, err := preserveIfPostLandGateFails(finalWD, req, gitOps, prep.targetRef, prep.currentTip, result.NewTip, prep.contribCount); err != nil {
				return err
			} else if preserved != nil {
				result = preserved
				syncFromRev = syncRev
				return nil
			}
			if req.EvidenceDir != "" {
				if err := copyEvidenceDirForLanding(projectRoot, finalWD, req.EvidenceDir); err != nil {
					return fmt.Errorf("copying evidence into landing worktree: %w", err)
				}
				if err := rewriteFinalResultArtifactForLand(finalWD, req, result); err != nil {
					return fmt.Errorf("rewriting final result artifact: %w", err)
				}
				if err := landEvidence(finalWD, prep.targetBranch, req, gitOps, result); err != nil {
					preserved, syncRev, preserveErr := preserveAfterEvidenceFailure(finalWD, req, gitOps, prep.targetRef, prep.currentTip, result.NewTip, prep.contribCount, err)
					if preserveErr != nil {
						return preserveErr
					}
					result = preserved
					syncFromRev = syncRev
					return nil
				}
				cleanupProjectEvidenceCopy(projectRoot, req.EvidenceDir)
			}
			syncFromRev = prep.currentTip
			return nil
		}

		// Merge path: the target has advanced since the worker started. Create
		// a temp detached worktree at currentTip and run `git merge --no-ff
		// ResultRev` inside it. The result is a merge commit whose parents are
		// [currentTip, ResultRev]. Crucially, ResultRev itself is NOT rewritten:
		// its parent is still BaseRev, so replay observes the original inputs.
		tempWT, tempWtErr := config.MkdirExecutionScratch(projectRoot, "ddx-land-wt-*")
		if tempWtErr != nil {
			return fmt.Errorf("creating temp worktree dir: %w", tempWtErr)
		}
		// os.MkdirTemp creates the dir, but git worktree add refuses to run if
		// the target already exists. Remove it first so git can recreate it.
		_ = os.RemoveAll(tempWT)
		if err := gitOps.AddWorktree(prep.worktreeDir, tempWT, prep.currentTip); err != nil {
			return fmt.Errorf("adding temp worktree at %s: %w", prep.currentTip, err)
		}
		defer func() { _ = gitOps.RemoveWorktree(prep.worktreeDir, tempWT) }()

		mergeMsg := fmt.Sprintf("Merge bead %s attempt %s into %s", req.BeadID, shortAttempt(req.AttemptID), prep.targetBranch)
		if err := gitOps.MergeInto(tempWT, req.ResultRev, mergeMsg); err != nil {
			// Merge conflict: preserve the original ResultRev and return.
			preserveRef := landIterationRef(req.BeadID, req.AttemptID, prep.currentTip)
			if upErr := gitOps.UpdateRefTo(prep.worktreeDir, preserveRef, req.ResultRev, ""); upErr != nil {
				return fmt.Errorf("preserving %s after merge conflict: %w", preserveRef, upErr)
			}
			result = &LandResult{
				Status:            "preserved",
				PreserveRef:       preserveRef,
				Reason:            "merge conflict",
				TargetBranch:      prep.targetBranch,
				MergedCommitCount: prep.contribCount,
			}
			return nil
		}

		// Merge clean: read the merge commit SHA from the temp worktree's HEAD
		// and fast-forward the target branch to it.
		mergeSHA, err := gitOps.HeadRevAt(tempWT)
		if err != nil {
			return fmt.Errorf("reading merge HEAD: %w", err)
		}
		if err := gitOps.UpdateRefTo(prep.worktreeDir, prep.targetRef, mergeSHA, lockedTip); err != nil {
			return fmt.Errorf("fast-forwarding %s to merge commit %s: %w", prep.targetRef, mergeSHA, err)
		}
		result = &LandResult{
			Status:            "landed",
			NewTip:            mergeSHA,
			LandedTip:         mergeSHA,
			TargetBranch:      prep.targetBranch,
			Merged:            true,
			MergedCommitCount: prep.contribCount,
		}
		finalWD, cleanup, err := landingFinalizationWorktree(projectRoot, prep.worktreeDir, prep.targetBranch, gitOps)
		if err != nil {
			return err
		}
		defer cleanup()
		if preserved, syncRev, err := preserveIfPostLandGateFails(finalWD, req, gitOps, prep.targetRef, prep.currentTip, result.NewTip, prep.contribCount); err != nil {
			return err
		} else if preserved != nil {
			result = preserved
			syncFromRev = syncRev
			return nil
		}
		if req.EvidenceDir != "" {
			if err := copyEvidenceDirForLanding(projectRoot, finalWD, req.EvidenceDir); err != nil {
				return fmt.Errorf("copying evidence into landing worktree: %w", err)
			}
			if err := rewriteFinalResultArtifactForLand(finalWD, req, result); err != nil {
				return fmt.Errorf("rewriting final result artifact: %w", err)
			}
			if err := landEvidence(finalWD, prep.targetBranch, req, gitOps, result); err != nil {
				preserved, syncRev, preserveErr := preserveAfterEvidenceFailure(finalWD, req, gitOps, prep.targetRef, prep.currentTip, result.NewTip, prep.contribCount, err)
				if preserveErr != nil {
					return preserveErr
				}
				result = preserved
				syncFromRev = syncRev
				return nil
			}
			cleanupProjectEvidenceCopy(projectRoot, req.EvidenceDir)
		}
		syncFromRev = prep.currentTip
		return nil
	})
	return result, syncFromRev, err
}

func preserveIfPostLandGateFails(wd string, req LandRequest, gitOps LandingGitOps, targetRef, preLandTip, landedTip string, contribCount int) (*LandResult, string, error) {
	if len(req.PostLandCommand) == 0 {
		return nil, "", nil
	}
	output, err := runPostLandCommand(wd, req.PostLandCommand)
	if err == nil {
		return nil, "", nil
	}

	preserveRef := landIterationRef(req.BeadID, req.AttemptID, preLandTip)
	if upErr := gitOps.UpdateRefTo(wd, preserveRef, req.ResultRev, ""); upErr != nil {
		return nil, "", fmt.Errorf("preserving %s after post-land gate: %w", preserveRef, upErr)
	}
	if revertErr := gitOps.UpdateRefTo(wd, targetRef, preLandTip, landedTip); revertErr != nil {

	if revertErr := gitOps.UpdateRefTo(wd, targetRef, preLandTip, landedTip); revertErr != nil {
		return nil, "", fmt.Errorf("restoring %s to %s after post-land gate failed: %w", targetRef, preLandTip, revertErr)
	}

	reason := fmt.Sprintf("post-land gate failed: %s: %v", strings.Join(req.PostLandCommand, " "), err)
	if trimmed := strings.TrimSpace(output); trimmed != "" {
		reason += ": " + truncatePostLandGateOutput(trimmed)
	}
	result := &LandResult{
		Status:            "preserved",
		PreserveRef:       preserveRef,
		Reason:            reason,
		TargetBranch:      req.TargetBranch,
		MergedCommitCount: contribCount,
	}
	return result, landedTip, nil
}

func preserveAfterEvidenceFailure(wd string, req LandRequest, gitOps LandingGitOps, targetRef, preLandTip, landedTip string, contribCount int, evidenceErr error) (*LandResult, string, error) {
	preserveRef := landIterationRef(req.BeadID, req.AttemptID, preLandTip)
	if upErr := gitOps.UpdateRefTo(wd, preserveRef, req.ResultRev, ""); upErr != nil {
		return nil, "", fmt.Errorf("preserving %s after evidence commit failure: %w", preserveRef, upErr)
	}
	if landedTip != "" {
		if revertErr := gitOps.UpdateRefTo(wd, targetRef, preLandTip, landedTip); revertErr != nil {
			return nil, "", fmt.Errorf("restoring %s to %s after evidence commit failed: %w", targetRef, preLandTip, revertErr)
		}
	}
	result := &LandResult{
		Status:            "preserved",
		PreserveRef:       preserveRef,
		Reason:            "evidence commit failed: " + evidenceErr.Error(),
		TargetBranch:      req.TargetBranch,
		MergedCommitCount: contribCount,
	}
	return result, landedTip, nil
}

func runPostLandCommand(wd string, command []string) (string, error) {
	if len(command) == 0 {
		return "", nil
	}
	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Minute)
	defer cancel()
	cmd := exec.CommandContext(ctx, command[0], command[1:]...)
	cmd.Dir = wd
	out, err := cmd.CombinedOutput()
	if ctx.Err() == context.DeadlineExceeded {
		return string(out), ctx.Err()
	}
	return string(out), err

